const rows = $input.all();
let watermark;

if (rows && rows.length > 0 && rows[0].json && rows[0].json.last_processed_sent_at) {
  watermark = rows[0].json.last_processed_sent_at;
} else {
  // First run ever — go back 7 days
  const d = new Date();
  d.setDate(d.getDate() - 7);
  watermark = d.toISOString();
}

// Unix timestamp for Gmail query
const unixTs = Math.floor(new Date(watermark).getTime() / 1000);

return [{ json: { watermark, unixTs } }];

