const item = $input.first().json;

function decodeBase64url(str) {
  if (!str) return '';
  return Buffer.from(str.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8');
}

function extractTextPlain(payload) {
  if (!payload) return '';

  // CASE 1: Direct body.data on payload (text/plain, no parts) ← this email's structure
  if (payload.mimeType === 'text/plain' && payload.body?.data) {
    return decodeBase64url(payload.body.data);
  }

  // CASE 2: Nested parts (multipart/alternative, multipart/mixed etc.)
  if (payload.parts && payload.parts.length > 0) {
    for (const part of payload.parts) {
      const result = extractTextPlain(part); // recursive
      if (result) return result;
    }
  }

  return '';
}

function stripQuotedReply(text) {
  const lines = text.split('\n');
  const replyLines = [];
  for (const line of lines) {
    if (line.startsWith('>')) break;
    if (/^On .+wrote:$/i.test(line.trim())) break;
    if (line.includes('---------- Forwarded message')) break;
    replyLines.push(line);
  }
  return replyLines.join('\n').replace(/\r/g, '').replace(/\n{3,}/g, '\n\n').trim();
}

let sentBody = extractTextPlain(item.payload);
sentBody = stripQuotedReply(sentBody);

if (!sentBody) sentBody = item.snippet || '';

const loopItem = $('🔄 Loop - Sent Emails').item.json;

return [{
  json: {
    ...loopItem,
    sentBody,
    threadId: item.threadId,
    messageId: item.id
  }
}];
